var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"……천사님.","JPN":"……天使様。","ENG":"...Angel.","TWN":"……天使。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"어쩌면 천사님이 하신 말씀이 사실일지도 몰라요.","JPN":"もしかしたら天使様の話が本当なのかもしれません。","ENG":"Maybe what you said was right after all.","TWN":"也許天使說的話是真的。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"과연, 그렇군요…….","JPN":"なるほど、そういうことですか……","ENG":"Oh, I see...","TWN":"果然，原來如此……"},"stage":{"bg":"MIND_FILM","slots":{"L":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 무장과 날개는 기계 장치의 마왕… 그 소체를 모방한 건가요?","JPN":"その武装や翼は機械装置の魔王……その構造を真似たのですか？","ENG":"Those armaments and wings... Are they modeled after the Demon Lord of Machinery?","TWN":"那武裝和翅膀是機械裝置的魔王……是模仿了那個軀體嗎？"},"stage":{"bg":"MIND_FILM","slots":{"L":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"맞아요. 천사님의 모습을 잠시 빌렸어요.","JPN":"そうです。ちょっとだけ天使様の姿を借りました。","ENG":"Yeah. I borrowed the angel's form for a bit.","TWN":"沒錯。我暫時借用了天使的模樣。"},"stage":{"bg":"MIND_FILM","slots":{"L":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"당신 말대로, 저는 무엇 하나 가지지 못한 가짜에 불과하지만…….","JPN":"あなたの言う通り、私は何一つ持っていない偽物ですけど……","ENG":"Like you said, I don't really have anything of my own...","TWN":"如你所說，我不過是個一無所有的冒牌貨……"},"stage":{"bg":"MIND_FILM","slots":{"L":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"반대로 그 무엇이든 될 수 있으니까요.","JPN":"だからこそ、何にだってなれます。","ENG":"But that means I can become anything.","TWN":"但相反，我也可以成為任何東西。"},"stage":{"bg":"MIND_FILM","slots":{"L":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"역시 당신은 저와 닮은 꼴이로군요, 세피라의 화신.","JPN":"やはりあなたは私に似ています、セフィラの化身。","ENG":"You really are like me, Personification of Sephira.","TWN":"果然你和我很相似啊，生命樹的化身。"},"stage":{"bg":"MIND_FILM","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"세계를 재구성할 신성에 다다랐으면서도, 마지막까지 자신이 아닌 타인의 것을 모방하다니.","JPN":"世界を再構成できる程の神聖に至っておきながら、最後まで自分ではない他人のものを模倣するとは。","ENG":"You reached the threshold of Divinity, yet even now, you're still imitating others.","TWN":"即便達到了能夠重構世界的神性，最後仍然模仿他人而非自我。"},"stage":{"bg":"MIND_FILM","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이래서야 저나 당신이나 결국 운명의 꼭두각시 신세로군요.","JPN":"これでは、私もあなたも運命の操り人形にすぎませんね。","ENG":"In the end, we're both just puppets of fate.","TWN":"看來我和你最終都是命運的傀儡啊。"},"stage":{"bg":"MIND_FILM","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"이 세상의 모든 것은, 마치 거대하고 차가운 기계처럼.","JPN":"この世界のすべては、まるで巨大で冷たい機械のように。","ENG":"Everything in this world feels like one giant, cold machine.","TWN":"這個世界上的一切，就像一台巨大而冰冷的機器。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"세계를 만드는 법칙에 의해, 전부 정해져 있던 걸지도 모른다고.","JPN":"世界を作る法則によって、全部決まっていたのかもしれないって。","ENG":"Maybe everything was already decided by the law of creating a world.","TWN":"也許一切都已經被創造世界的法則所決定了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"아니요. 저는 인간이에요.","JPN":"いいえ、私は人間です。","ENG":"No. I'm human.","TWN":"不，我是人類。"},"stage":{"bg":"MIND_FILM","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"인간은 누구나 다른 사람에게 도움을 받고 살아요.","JPN":"人間は誰だって、他の人に助けられながら生きています。","ENG":"And humans live with help from others.","TWN":"人類無論是誰，都是依靠他人的幫助而生活的。"},"stage":{"bg":"MIND_FILM","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"힘들 때는 손을 내밀어도 괜찮아요. 그건 부끄러운 게 아니니까요.","JPN":"辛い時は手を伸ばしても大丈夫です。それは恥ずかしいことじゃありません。","ENG":"It's okay to reach out when you're struggling. There's nothing shameful about that.","TWN":"困難的時候，伸出手來求助也沒關係。這並不是什麼？恥的事情。"},"stage":{"bg":"MIND_FILM","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"대신, 도움을 받았다면 언젠가 그 도움을 돌려줄 수 있어야 해요.","JPN":"その代わり、助けてもらったのなら、いつかそれを返せるようにならないといけないんです。","ENG":"But if you receive help, you have to return it someday.","TWN":"相應的，如果得到了幫助，總有一天也要回報這份幫助。"},"stage":{"bg":"MIND_FILM","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"미나 선배, 에이미 씨, 펠리세트와 라이카… 모두 저를 구하기 위해 여기까지 와주었어요.","JPN":"ミナ先輩、エイミーさん、フェリセットとライカ……みんな私を助けるためにここまで来てくれました。","ENG":"Mina, Amy, Félicette, and Laika... they all came here to save me.","TWN":"米娜前輩，艾米，費莉塞特和萊卡……大家都是為了救我才來到這裡的。"},"stage":{"bg":"MIND_FILM","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"그러니까 저도 그 도움에 반드시 보답하고 싶어요.","JPN":"だから私も絶対、それを返したいです。","ENG":"So I want to repay them.","TWN":"所以，我也一定想要回報那份幫助。"},"stage":{"bg":"MIND_FILM","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"그런 게 바로 <color=#ffd34c>인연</color>일 테니까.","JPN":"それが<color=#ffd34c>絆</color>でしょうから。","ENG":"That's what a <color=#ffd34c>bond</color> is.","TWN":"那就是所謂的<color=#ffd34c>緣分</color>吧。"},"stage":{"bg":"MIND_FILM","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"물러서, 스완!","JPN":"下がれ、スワン！","ENG":"Back off, Swan!","TWN":"退後，史旺！"},"stage":{"bg":"MIND_FILM","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"두 번 다시 노엘에게 접근하게 두지 않을 테니까……!","JPN":"二度とノエルには近づけさせない……！","ENG":"I won't let you get anywhere near Noelle again...!","TWN":"我絕不會再讓你接近洛艾兒！"},"stage":{"bg":"MIND_FILM","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"큭…! 제법 끈질기군요 늑대……!","JPN":"くっ……！　なかなかしぶといですね、オオカミ……！","ENG":"Kgh...! Still clinging on, Wolf...?!","TWN":"咳！你還真是頑強呢，狼……！"},"stage":{"bg":"MIND_FILM","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어이, 스완! 지금 어딜 보는 거야……?","JPN":"おい、スワン！　どこ見てんだよ！","ENG":"Hey, Swan! Look at me...!","TWN":"喂，史旺！？現在在看哪裡？"},"stage":{"bg":"MIND_FILM","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};